// Familles disponibles
const PLIALU_MAT_FAMILIES = ['Alu laqué', 'Aluminium standard', 'Aluminium brut', 'Acier laqué', 'Acier standard', 'Acier brut'];

// Helper : recherche matières par texte (nom, RAL, finition)
function searchMaterials(query, maxResults = 20) {
  if (!query || query.length < 2) return [];
  const q = query.toLowerCase();
  return PLIALU_MATERIALS
    .filter(m => m.name.toLowerCase().includes(q) ||
                 m.ral.toLowerCase().includes(q) ||
                 m.finish.toLowerCase().includes(q))
    .slice(0, maxResults);
}

// Helper : récupérer une matière par ID exact
function getMaterialById(id) {
  return PLIALU_MATERIALS.find(m => m.id === id) || null;
}

// Helper : matières par famille
function getMaterialsByFamily(family) {
  return PLIALU_MATERIALS.filter(m => m.family === family);
}